from dataclasses import dataclass
from datetime import datetime
from enum import Enum

class PatchRole(str, Enum):
    INCIDENT_COMMANDER  = "incident_commander"
    PATCH_ENGINEER      = "patch_engineer"
    SECURITY_REVIEWER   = "security_reviewer"
    COMMUNICATIONS_LEAD = "communications_lead"
    OBSERVER            = "observer"

@dataclass
class EmergencyPatchCommand:
    cve_id: str
    started_at: datetime
    roles: dict[PatchRole, str]    # role -> name/handle
    channel: str
    update_interval_minutes: int = 30

    def ic(self) -> str:
        return self.roles.get(PatchRole.INCIDENT_COMMANDER, "unassigned")

    def has_required_roles(self) -> bool:
        required = {
            PatchRole.INCIDENT_COMMANDER,
            PatchRole.PATCH_ENGINEER,
            PatchRole.SECURITY_REVIEWER,
        }
        return required.issubset(self.roles.keys())

    def status_template(self, elapsed_minutes: float) -> str:
        return (
            f"[{self.channel}] T+{elapsed_minutes:.0f}m update\n"
            f"IC: {self.ic()}\n"
            f"Status: [DESCRIBE CURRENT PHASE]\n"
            f"Next update in {self.update_interval_minutes} min or on phase change."
        )
